glsl3.vert:
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
precision highp float;
in vec3 a_position;
in vec2 a_uv0;
out vec2 uv0;
void main () {
    gl_Position = cc_matViewProj * vec4(a_position, 1);
    uv0 = a_uv0;
}

glsl3.frag:
precision highp float;
  in vec2 uv0;
uniform sampler2D texture;
  uniform sampler2D u_fluxayTexture;
  uniform ARGS {
      vec4  u_UVoffset;
      float u_startPos;
      float u_rotated;
      float u_time;
      float u_fluxaySpeed;
  };
  void main()
  {
      vec2 UVnormalize;
      UVnormalize.x = (uv0.x-u_UVoffset.x)/(u_UVoffset.z-u_UVoffset.x);
      UVnormalize.y = (uv0.y-u_UVoffset.y)/(u_UVoffset.w-u_UVoffset.y);
      if(u_rotated > 0.5)
      {
          float temp = UVnormalize.x;
          UVnormalize.x = UVnormalize.y;
          UVnormalize.y = 1.0 - temp;
      }
      vec4 src_color = texture2D(texture, uv0).rgba;
      vec2 flow_uv = vec2(UVnormalize.x,UVnormalize.y);
      flow_uv.x -= (u_time*u_fluxaySpeed)+u_startPos;
      vec4 src_color1 = texture2D(u_fluxayTexture, flow_uv).rgba;
      if(src_color.a >= 1.0) {
          gl_FragColor = src_color+src_color1;
      }
      else {
          gl_FragColor = src_color;
      }
  }

